/* Blog / Article Card */
.blog-card {
  background: var(--card-bg, #ffffff);
  border-radius: var(--card-radius, 20px);
  border: 1px solid var(--card-border, #f1f5f9);
  box-shadow: var(--card-shadow, 0 2px 12px rgba(0,0,0,0.06));
  overflow: hidden;
  display: flex;
  flex-direction: column;
  transition: transform 0.3s ease, box-shadow 0.3s ease;
}
.blog-card:hover {
  transform: translateY(-5px);
  box-shadow: 0 16px 40px rgba(0,0,0,0.10);
}

/* Cover */
.blog-card-cover {
  position: relative;
  overflow: hidden;
  aspect-ratio: 16/9;
}
.blog-card-cover img {
  width: 100%;
  height: 100%;
  object-fit: cover;
  transition: transform 0.4s ease;
}
.blog-card:hover .blog-card-cover img {
  transform: scale(1.06);
}
.blog-card-category {
  position: absolute;
  top: 14px;
  left: 14px;
  background: #6366f1;
  color: #fff;
  font-size: 11px;
  font-weight: 700;
  padding: 4px 12px;
  border-radius: 20px;
  text-transform: uppercase;
  letter-spacing: 0.5px;
}
[dir="rtl"] .blog-card-category { left: auto; right: 14px; }

/* Body */
.blog-card-body {
  padding: 22px;
  display: flex;
  flex-direction: column;
  gap: 12px;
  flex: 1;
}
.blog-meta {
  display: flex;
  gap: 12px;
  font-size: 12px;
  color: #94a3b8;
}
.blog-read-time::before { content: '⏱ '; }
.blog-title {
  font-size: var(--title-font-size, 19px);
  font-weight: var(--title-font-weight, 700);
  color: var(--title-color, #0f172a);
  line-height: 1.4;
  margin: 0;
  letter-spacing: -0.2px;
  display: -webkit-box;
  -webkit-line-clamp: 2;
  -webkit-box-orient: vertical;
  overflow: hidden;
}
.blog-excerpt {
  font-size: var(--description-font-size, 14px);
  color: var(--description-color, #64748b);
  line-height: var(--description-line-height, 1.65);
  margin: 0;
  display: -webkit-box;
  -webkit-line-clamp: 3;
  -webkit-box-orient: vertical;
  overflow: hidden;
  flex: 1;
}

/* Author */
.blog-author {
  display: flex;
  align-items: center;
  gap: 10px;
  padding-top: 14px;
  border-top: 1px solid var(--card-border, #f1f5f9);
  margin-top: auto;
}
.blog-avatar {
  width: 36px;
  height: 36px;
  border-radius: 50%;
  object-fit: cover;
  flex-shrink: 0;
}
.blog-author-name {
  font-size: var(--author-font-size, 13px);
  font-weight: var(--author-font-weight, 600);
  color: var(--author-color, #334155);
  margin: 0;
}
.blog-author-role {
  font-size: var(--role-font-size, 12px);
  color: var(--role-color, #94a3b8);
  margin: 0;
}

/* Dark Mode */
.dark .blog-card, [data-theme="dark"] .blog-card {
  background: #1e293b;
  border-color: #334155;
}
.dark .blog-title, [data-theme="dark"] .blog-title { color: #f1f5f9; }
.dark .blog-excerpt, [data-theme="dark"] .blog-excerpt { color: #94a3b8; }
.dark .blog-author, [data-theme="dark"] .blog-author { border-color: #334155; }
.dark .blog-author-name, [data-theme="dark"] .blog-author-name { color: #e2e8f0; }

/* RTL */
[dir="rtl"] .blog-author { flex-direction: row-reverse; }
[dir="rtl"] .blog-meta { flex-direction: row-reverse; }
[dir="rtl"] .blog-title,
[dir="rtl"] .blog-excerpt { text-align: right; }
